# tests/load/check_thresholds.py
"""
Evaluate Locust CSV results against thresholds.yaml.
Usage: python check_thresholds.py /tmp/load-results_stats.csv tests/load/thresholds.yaml
Exit code 0 = all pass, 1 = one or more failures.
"""
import csv
import sys
import yaml
from pathlib import Path

def load_stats(csv_path: str) -> dict[str, dict]:
    rows = {}
    with open(csv_path) as f:
        for row in csv.DictReader(f):
            rows[row["Name"]] = row
    return rows

def check(stats: dict[str, dict], thresholds: list[dict]) -> list[str]:
    failures = []
    for t in thresholds:
        name = t["request_name"]
        if name not in stats:
            failures.append(f"No data for '{name}' — was the request name correct?")
            continue
        row = stats[name]
        metric = t["metric"]
        field_map = {
            "p50_response_time_ms": "50%",
            "p99_response_time_ms": "99%",
            "failure_rate_pct": "Failure Count",  # computed below
            "requests_per_second": "Requests/s",
        }
        field = field_map.get(metric)
        if field is None:
            failures.append(f"Unknown metric: {metric}")
            continue
        if metric == "failure_rate_pct":
            total = int(row.get("Request Count", 0))
            failed = int(row.get("Failure Count", 0))
            value = (failed / total * 100) if total else 0.0
        else:
            value = float(row.get(field, 0))

        if "max" in t and value > t["max"]:
            failures.append(
                f"FAIL [{t['description']}]: {metric}={value:.1f} > max={t['max']}"
            )
        if "min" in t and value < t["min"]:
            failures.append(
                f"FAIL [{t['description']}]: {metric}={value:.1f} < min={t['min']}"
            )
    return failures

if __name__ == "__main__":
    stats = load_stats(sys.argv[1])
    thresholds = yaml.safe_load(Path(sys.argv[2]).read_text())["thresholds"]
    failures = check(stats, thresholds)
    for f in failures:
        print(f)
    if failures:
        print(f"\n{len(failures)} threshold(s) failed.")
        sys.exit(1)
    print(f"All {len(thresholds)} thresholds passed.")
